action.old_str:
// Return true if `L` writes to `ptr` anywhere.
bool
loopWritesToPtr(Loop* L, Value* ptr)
{
  for (auto* bb : L->blocks()) {
    for (auto& I : *bb) {
      if (auto si = dyn_cast<StoreInst>(&I)) {
        if (si->getPointerOperand() == ptr)
          return true;
      }
      if (isa<CallBase>(I))
        return true;
    }
  }
  return false;
}

action.new_str:
// Returns true if `L` writes (other than the given `excluded` store) to `ptr`.
bool
loopWritesToPtr(Loop* L, Value* ptr, StoreInst* excluded = nullptr)
{
  for (auto* bb : L->blocks()) {
    for (auto& I : *bb) {
      if (auto si = dyn_cast<StoreInst>(&I)) {
        if (si == excluded)
          continue;
        if (si->getPointerOperand() == ptr)
          return true;
        // Conservative: any other store may alias.  We accept the false
        // positive for correctness.
        return true;
      }
      if (isa<CallBase>(I))
        return true;
    }
  }
  return false;
}

